import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.brm5GKsQ.js";const g=JSON.parse('{"title":"Why Flexture?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why-flexture.md","filePath":"guide/why-flexture.md"}'),n={name:"guide/why-flexture.md"};function s(i,e,d,l,h,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="why-flexture" tabindex="-1">Why Flexture? <a class="header-anchor" href="#why-flexture" aria-label="Permalink to &quot;Why Flexture?&quot;">​</a></h1><p><a href="https://yogalayout.dev/" target="_blank" rel="noreferrer">Yoga</a> is the industry standard flexbox engine, used by React Native, Ink, and thousands of apps. It&#39;s mature and battle-tested. But it&#39;s C++ compiled to WASM, and that creates real problems for JavaScript applications.</p><h2 id="the-problems-with-wasm" tabindex="-1">The Problems with WASM <a class="header-anchor" href="#the-problems-with-wasm" aria-label="Permalink to &quot;The Problems with WASM&quot;">​</a></h2><p><strong>Async initialization.</strong> Yoga requires <code>await Yoga.init()</code> before creating any nodes. No synchronous startup, no use at module load time, no use in config files or build scripts. For CLIs that should start instantly, this adds latency and complexity.</p><p><strong>WASM boundary crossing.</strong> Every method call (<code>setWidth</code>, <code>setFlexGrow</code>, etc.) crosses the JS-to-WASM boundary. Node creation is ~8x more expensive than a JS object. For TUIs that rebuild layout trees per render, this dominates.</p><p><strong>Memory growth.</strong> WASM linear memory grows but never shrinks. Yoga&#39;s yoga-wasm-web has a <a href="https://github.com/nicolo-ribaudo/yoga-wasm-web/issues/1" target="_blank" rel="noreferrer">known memory growth bug</a> where each node allocation permanently grows the WASM heap. In long-running apps, this caused <a href="https://github.com/anthropics/claude-code/issues/4953" target="_blank" rel="noreferrer">120GB RAM usage in Claude Code</a>.</p><p><strong>Debugging opacity.</strong> You can&#39;t step into WASM in a JS debugger. When layout is wrong, you get a computed number with no way to inspect the algorithm&#39;s intermediate state. Flexture is readable JS -- set a breakpoint in <code>layout-zero.ts</code>.</p><p><strong>No tree-shaking.</strong> The WASM binary is monolithic. You get the entire engine even if you use a fraction of the features.</p><h2 id="flexture-s-approach" tabindex="-1">Flexture&#39;s Approach <a class="header-anchor" href="#flexture-s-approach" aria-label="Permalink to &quot;Flexture&#39;s Approach&quot;">​</a></h2><p>Flexture fills the gap that Facebook&#39;s original pure-JS flexbox engine (<code>css-layout</code>) left when they moved to C++. Full CSS flexbox spec, Yoga-compatible API, pure JS, zero WASM.</p><table tabindex="0"><thead><tr><th>Concern</th><th>Yoga</th><th>Flexture</th></tr></thead><tbody><tr><td><strong>Runtime</strong></td><td>WebAssembly</td><td>Pure JavaScript</td></tr><tr><td><strong>Initialization</strong></td><td>Async (WASM load)</td><td>Synchronous</td></tr><tr><td><strong>Dependencies</strong></td><td>WASM runtime required</td><td><code>debug</code> (optional)</td></tr><tr><td><strong>Debugging</strong></td><td>WASM stack traces</td><td>Native JS stack traces</td></tr><tr><td><strong>Bundle size</strong></td><td>117 KB minified</td><td>47 KB minified</td></tr></tbody></table><h2 id="performance-trade-offs" tabindex="-1">Performance Trade-offs <a class="header-anchor" href="#performance-trade-offs" aria-label="Permalink to &quot;Performance Trade-offs&quot;">​</a></h2><p>Each engine wins in different scenarios:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Winner</th><th>Margin</th></tr></thead><tbody><tr><td><strong>Initial layout</strong></td><td>Flexture</td><td>1.5-2.5x</td></tr><tr><td><strong>No-change re-layout</strong></td><td><strong>Flexture</strong></td><td><strong>5.5x</strong></td></tr><tr><td><strong>Single dirty leaf</strong></td><td>Yoga</td><td>2.8-3.4x</td></tr><tr><td><strong>Deep nesting (15+)</strong></td><td>Yoga</td><td>increasing</td></tr></tbody></table><p>For interactive TUIs where most keystrokes don&#39;t change layout, Flexture&#39;s fingerprint cache makes re-layout essentially free (27ns regardless of tree size).</p><p>See <a href="/flexture/guide/performance.html">Performance</a> for detailed benchmarks.</p><h2 id="use-flexture-when" tabindex="-1">Use Flexture When <a class="header-anchor" href="#use-flexture-when" aria-label="Permalink to &quot;Use Flexture When&quot;">​</a></h2><ul><li>You want synchronous initialization (no async <code>await init()</code>)</li><li>You&#39;re in an environment where WASM is awkward (older bundlers, edge runtimes)</li><li>You want smaller bundles (2.5-3.5x) and simpler debugging</li><li>You&#39;re building interactive TUIs where no-change re-layout dominates</li></ul><h2 id="use-yoga-when" tabindex="-1">Use Yoga When <a class="header-anchor" href="#use-yoga-when" aria-label="Permalink to &quot;Use Yoga When&quot;">​</a></h2><ul><li>Your primary workload is frequent incremental re-layout of large pre-existing trees</li><li>You have deep nesting (15+ levels) as your primary use case</li><li>You&#39;re already using React Native or another Yoga-based system</li><li>You need the battle-tested stability of a mature project</li></ul>',20)])])}const p=t(n,[["render",s]]);export{g as __pageData,p as default};
